def get_svg(name: str, color: str = "#0066CC", size: int = 24) -> str:
    """获取替换好颜色、尺寸的 SVG 字符串。"""
    svg = ICONS.get(name, ICONS.get("x", ""))
    # 将 currentColor 替换为指定颜色
    svg = svg.replace('stroke="currentColor"', f'stroke="{color}"')
    svg = svg.replace('fill="currentColor"', f'fill="{color}"')
    # 替换 width/height
    svg = svg.replace('width="24"', f'width="{size}"')
    svg = svg.replace('height="24"', f'height="{size}"')
    return svg


def render_icon(name: str, size: int = 24, color: str = "#0066CC") -> Optional[QPixmap]:
    """渲染 SVG 图标为 QPixmap；不可用时返回 None。"""
    if not HAS_QTSVG:
        return None
    try:
        svg_bytes = get_svg(name, color, size).encode("utf-8")
        renderer = QSvgRenderer(svg_bytes)
        pixmap = QPixmap(size, size)
        pixmap.fill(Qt.GlobalColor.transparent)
        painter = QPainter(pixmap)
        painter.setRenderHint(QPainter.RenderHint.Antialiasing)
        renderer.render(painter)
        painter.end()
        return pixmap
    except Exception:
        return None


def icon_label(name: str, size: int = 24, color: str = "#0066CC",
               bg_color: Optional[str] = None, radius: int = 8,
               parent=None) -> "QLabel":
    """创建带 SVG 图标的 QLabel；SVG 不可用时回退到圆角色块。"""
    from PyQt6.QtWidgets import QLabel
    from PyQt6.QtGui import QPixmap

    lbl = QLabel(parent)
    lbl.setFixedSize(size, size)
    lbl.setAlignment(Qt.AlignmentFlag.AlignCenter)

    pixmap = render_icon(name, size - 8, color)
    if pixmap is not None and not pixmap.isNull():
        style = "background: transparent; border: none;"
        if bg_color:
            style = f"background-color: {bg_color}; border-radius: {radius}px;"
        lbl.setStyleSheet(style)
        lbl.setPixmap(pixmap)
        return lbl

    # 回退：纯色圆块 + 首字母
    fallback = name[0].upper() if name else "?"
    style = f"""
        background-color: {bg_color or '#E6F2FF'};
        color: {color};
        border-radius: {radius}px;
        font-size: {size // 2 - 2}px;
        font-weight: 700;
    """
    lbl.setText(fallback)
    lbl.setStyleSheet(style)
    return lbl
